ALTER TABLE `real_estate_ecm`.`maintenance`.`vendor_dispatch` ADD CONSTRAINT `fk_maintenance_vendor_dispatch_pm_schedule_id` FOREIGN KEY (`pm_schedule_id`) REFERENCES `real_estate_ecm`.`maintenance`.`pm_schedule`(`pm_schedule_id`);
ALTER TABLE `real_estate_ecm`.`maintenance`.`vendor_dispatch` ADD CONSTRAINT `fk_maintenance_vendor_dispatch_service_contract_id` FOREIGN KEY (`service_contract_id`) REFERENCES `real_estate_ecm`.`maintenance`.`service_contract`(`service_contract_id`);
